#include <iostream>
using namespace std;

class Base {
protected:
 int* baseData;
public:
 Base() { 
 baseData = new int(100); 
 cout << "Base Constructor: Allocated " << *baseData << endl; 
 }
 virtual ~Base() { 
 cout << "Base Destructor: Cleaning up baseData" << endl;
 delete baseData; 
 }
};

class Derived : public Base {
private:
 int* derivedData;
public:
 Derived() { 
 derivedData = new int(200); 
 cout << "Derived Constructor: Allocated " << *derivedData << endl; 
 }
 ~Derived() { 
 cout << "Derived Destructor: Cleaning up derivedData" << endl;
 delete derivedData; 
 }
};

int main() {
 Base* ptr = new Derived();
 cout << "Deleting through base pointer..." << endl;
 delete ptr; // With virtual destructor: calls Derived then Base
 // Without virtual: only Base destructor, memory leak!
 return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
 Base() { cout << "Base Constructor" << endl; }
 ~Base() { cout << "Base Destructor" << endl; }
};

class Derived : public Base {
public:
 Derived() { cout << "Derived Constructor" << endl; }
 ~Derived() { cout << "Derived Destructor" << endl; }
};

int main() {
 cout << "Creating Derived object..." << endl;
 Derived obj;
 cout << "Object going out of scope..." << endl;
 return 0;
}

// Output:
// Creating Derived object...
// Base Constructor
// Derived Constructor
// Object going out of scope...
// Derived Destructor
// Base Destructor

#include <iostream>
#include <fstream>
using namespace std;

class FileHandler {
private:
 ofstream file;
 string filename;
 bool isOpen;
public:
 FileHandler(const string& name) : filename(name), isOpen(false) {
 file.open(filename);
 if(file.is_open()) {
 isOpen = true;
 cout << "File opened: " << filename << endl;
 }
 }

 void write(const string& data) {
 if(isOpen) file << data;
 }

 ~FileHandler() {
 if(isOpen) {
 file.close();
 cout << "File closed in destructor: " << filename << endl;
 }
 }
};

void processFile() {
 FileHandler handler("data.txt");
 handler.write("Hello, RAII!");
 // Destructor called automatically when handler goes out of scope
 // File is properly closed even if exception occurs
}

int main() {
 processFile();
 cout << "Resource automatically cleaned up!" << endl;
 return 0;
}

#include <iostream>
using namespace std;

class A {
public:
 A() { cout << "A Constructor" << endl; }
 virtual ~A() { cout << "A Destructor" << endl; }
};

class B {
public:
 B() { cout << "B Constructor" << endl; }
 virtual ~B() { cout << "B Destructor" << endl; }
};

class C : public A, public B {
public:
 C() { cout << "C Constructor" << endl; }
 ~C() { cout << "C Destructor" << endl; }
};

int main() {
 cout << "=== Creating C object ===" << endl;
 C* obj = new C();

 cout << "\n=== Deleting through A* ===" << endl;
 A* ptrA = obj;
 delete ptrA;

 // Note: Only A's part properly cleaned, B's destructor not called!
 // This is why all base classes in polymorphism need virtual destructors
 return 0;
}

// Proper deletion:
// C* obj = new C();
// delete obj; // Calls C, B, A destructors in correct order

#include <iostream>
using namespace std;

class AbstractBase {
public:
 // Pure virtual destructor - MUST have implementation
 virtual ~AbstractBase() = 0;

 virtual void display() = 0;
};

// Pure virtual destructor MUST be defined
AbstractBase::~AbstractBase() {
 cout << "AbstractBase virtual destructor called" << endl;
}

class Concrete : public AbstractBase {
private:
 int* data;
public:
 Concrete() { data = new int(42); }

 ~Concrete() {
 cout << "Concrete destructor: freeing data" << endl;
 delete data;
 }

 void display() { cout << "Data: " << *data << endl; }
};

int main() {
 // AbstractBase obj; // Error: cannot instantiate abstract class
 Concrete obj; // OK: Concrete is not abstract
 obj.display();

 AbstractBase* ptr = new Concrete();
 delete ptr; // Properly calls Concrete then AbstractBase destructors
 return 0;
}
